const target = $('Deep Research Trigger').item.json.body.target;
const type = $('Deep Research Trigger').item.json.body.type;
const queries = [];
if (type === 'competitor') {
  queries.push({ focus: 'contracts', query: 'What are the most recent federal government contract awards won by ' + target + ' in 2024-2026? Include contract values, agencies, and program names. Focus on defense and intelligence contracts.' });
  queries.push({ focus: 'competitive', query: 'What are ' + target + ' key capabilities, teaming partners, recent acquisitions, and strategic moves in the defense contracting market? Include any hiring patterns or job postings that signal new work areas.' });
  queries.push({ focus: 'strategic', query: 'What is ' + target + ' competitive position in defense IT services, systems engineering, and technical assistance (SETA) contracts? What are their strengths, weaknesses, and market focus areas?' });
} else if (type === 'program') {
  queries.push({ focus: 'program_status', query: 'What is the current status of the ' + target + ' defense program? Include budget, timeline, key milestones, and any recent solicitations or contract actions.' });
  queries.push({ focus: 'requirements', query: 'What are the technical requirements and capability needs for the ' + target + ' program? What technologies and services are being sought?' });
  queries.push({ focus: 'competitive_landscape', query: 'Who are the current contractors and likely competitors for the ' + target + ' program? What are the incumbent contract details?' });
} else if (type === 'agency') {
  queries.push({ focus: 'budget', query: 'What is the latest budget information and spending priorities for ' + target + '? Include FY2025-2026 budget requests, key programs, and modernization initiatives.' });
  queries.push({ focus: 'contracts', query: 'What are the major recent contract awards and upcoming solicitations from ' + target + '? Focus on IT services, systems engineering, and technical assistance.' });
  queries.push({ focus: 'leadership', query: 'Who are the key leaders and decision makers at ' + target + '? What are their stated priorities and strategic direction?' });
} else {
  queries.push({ focus: 'overview', query: 'Provide a comprehensive overview of ' + target + ' in the context of US defense contracting. Include recent contract activity, key stakeholders, and market dynamics.' });
  queries.push({ focus: 'competitive', query: 'What is the competitive landscape around ' + target + '? Who are the key players and what opportunities exist for mid-tier defense contractors?' });
  queries.push({ focus: 'intelligence', query: 'What are the latest developments, news, and changes related to ' + target + '? Focus on 2025-2026 activity.' });
}
return queries.map(function(q) { return { json: { focus: q.focus, query: q.query, target: target, type: type } }; });

