const items = $('Perplexity Deep Search').all();
const target = $('Deep Research Trigger').item.json.body.target;
const type = $('Deep Research Trigger').item.json.body.type;
const opp_id = $('Deep Research Trigger').item.json.body.opp_id || null;
const research = [];
let totalCitations = 0;
for (var i = 0; i < items.length; i++) {
  const item = items[i].json;
  const queryItems = $('Build Research Queries').all();
  const focus = queryItems[i] ? queryItems[i].json.focus : 'unknown';
  const content = item.choices ? item.choices[0].message.content : (item.error ? 'Error: ' + JSON.stringify(item.error) : 'No response');
  const citations = item.citations || [];
  totalCitations += citations.length;
  research.push({ focus: focus, content: content.substring(0, 3000), citations: citations.slice(0, 10), model: item.model || 'unknown' });
}
return [{ json: { target: target, type: type, opp_id: opp_id, research: research, total_citations: totalCitations, research_count: research.length } }];

