const response = $input.first().json;
const text = response.content ? response.content[0].text : '{}';
var report;
try {
  var cleaned = text.replace(/```json\n?|```/g, '').trim();
  report = JSON.parse(cleaned);
} catch(e) {
  report = { executive_summary: text.substring(0, 2000), error: 'Failed to parse structured report', raw: text.substring(0, 3000) };
}
const collectData = $('Collect Research Results').first().json;
return [{ json: { report: report, target: collectData.target, type: collectData.type, opp_id: collectData.opp_id, timestamp: new Date().toISOString() }, pairedItem: { item: 0 } }];

