const parsed = $('Parse Report').first().json;
const storeOut = $('Store Research').first().json;
const researchId = (storeOut && storeOut.id) ? storeOut.id : (Array.isArray(storeOut) && storeOut[0] && storeOut[0].id) ? storeOut[0].id : Date.now();
const report = parsed.report || {};
const findings = Array.isArray(report.key_findings) ? report.key_findings.slice(0,5).map(f => f.finding || '').join(' | ') : '';
const capImpl = report.capture_implications || {};
const actions = Array.isArray(capImpl.recommended_actions) ? capImpl.recommended_actions.slice(0,5).join(' | ') : '';
const text = (report.executive_summary || '') + '\n\nKey Findings: ' + findings + '\n\nRecommended Actions: ' + actions;
return [{
  json: {
    payload: {
      source_type: 'deep_research',
      items: [{
        id: 'dr-' + researchId,
        title: 'Deep Research: ' + (parsed.target || 'Unknown') + ' (' + (parsed.type || 'unknown') + ')',
        text: text.substring(0, 9000),
        chunk_index: 0,
        metadata: {
          source: 'deep_research',
          research_type: parsed.type,
          target: parsed.target,
          opp_id: parsed.opp_id,
          confidence: report.confidence_rating || 'MEDIUM',
          sources_used: report.sources_used || 0,
          timestamp: parsed.timestamp
        }
      }]
    },
    research_id: researchId,
    target: parsed.target,
    type: parsed.type,
    report: report,
    opp_id: parsed.opp_id,
    timestamp: parsed.timestamp
  }
}];
